class InvalidTemperatureError(Exception):
    pass

def set_temperature(temp):
    if temp < -273.15:
        raise InvalidTemperatureError(
            f"{temp} is below absolute zero (-273.15). That is physically impossible."
        )
    if temp > 1000000:
        raise InvalidTemperatureError(
            f"{temp} exceeds the maximum allowed temperature of 1,000,000 degrees."
        )
    print(f"Temperature set to {temp} degrees.")

try:
    set_temperature(100)
except InvalidTemperatureError as e:
    print(f"Error: {e}")

try:
    set_temperature(-300)
except InvalidTemperatureError as e:
    print(f"Error: {e}")

try:
    set_temperature(2000000)
except InvalidTemperatureError as e:
    print(f"Error: {e}")
